export class AwsClient { constructor(options) { this.options = options; } async send() { return {}; } }
export class AwsClientError extends Error { constructor(msg, code) { super(msg); this.statusCode = code; } }
export class AwsCredentialProviderError extends Error { constructor(msg) { super(msg); this.name = 'AwsCredentialProviderError'; } }
